#include <iostream>
#include <cmath>
#include <iomanip>
using namespace std;

int main()
{
	long long a,c=0,b[10001]={ },max=0,cnt=0,z=0;
	cin>>a;
	for(int i=1;i<=a;i++){
		cin>>b[i];
		c+=b[i];
		if(b[i]>max) max=b[i];
	}
	int i;
	for(i=1;i<=a;i++){
		if(b[i]==max){
			cnt+=1;
		}	
	}
	cout<<c-cnt*max;
	return 0;
}
